      )
      port map(
        clk => clk,
        clk_write => clk,
        clk_read => clk_input,
        --
        write_ready => output_m2s.ready,
        write_valid => output_s2m.valid,
        write_data => write_data,
        --
        read_ready => input_m2s.ready,
        read_valid => read_valid,
        read_data => read_data
      );

  end generate;

end architecture;

